const payload = ($json.body && typeof $json.body === 'object') ? $json.body : $json;

const rawQuery = payload.query;
if (typeof rawQuery !== 'string' || rawQuery.trim() === '') {
  throw new Error('Request body must include a string field named query.');
}

let projectSlug = null;
if (payload.project_slug !== undefined && payload.project_slug !== null) {
  if (typeof payload.project_slug !== 'string') {
    throw new Error('project_slug must be a string when provided');
  }

  const trimmed = payload.project_slug.trim();
  projectSlug = trimmed || null;
}

return [{
  json: {
    query: rawQuery.trim(),
    projectSlug
  }
}];

const base = $('Normalize Input').first().json;
const rows = $input.all().map(item => item.json ?? {});

if (!base.projectSlug) {
  return [{ json: base }];
}

const firstRow = rows[0] ?? {};

const isValid =
  firstRow.project_slug_valid === true ||
  firstRow.project_slug === base.projectSlug;

if (!isValid) {
  throw new Error(`Unknown project_slug: ${base.projectSlug}`);
}

return [{ json: base }];

const base = $('Enforce Project Validation Code').first().json;
const embeddings = $json.embeddings;

if (!Array.isArray(embeddings) || !Array.isArray(embeddings[0])) {
  throw new Error('Ollama response did not contain embeddings[0].');
}

const vector = embeddings[0];
const vectorLiteral = `[${vector.join(',')}]`;

return [{
  json: {
    query: base.query,
    projectSlug: base.projectSlug,
    vector_literal: vectorLiteral
  }
}];

const base = $('Enforce Project Validation Code').first().json;
const rows = $input.all().map(item => item.json ?? {});

const memories = rows.map((row) => {
  const metadata = row.metadata_json && typeof row.metadata_json === 'object' ? row.metadata_json : {};
  const memoryProjectSlug = typeof metadata.project_slug === 'string' && metadata.project_slug.trim() !== ''
    ? metadata.project_slug.trim()
    : null;

  return {
    id: row.id,
    title: row.title ?? '',
    category: row.category ?? '',
    source: row.source ?? '',
    content: row.content ?? '',
    similarity: row.similarity,
    projectSlug: memoryProjectSlug,
    metadata_json: metadata
  };
});

const contextBlock = memories.length
  ? memories.map((memory, index) => {
      const lines = [
        `Memory ${index + 1}`,
        `Title: ${memory.title}`,
        `Category: ${memory.category}`,
        `Source: ${memory.source}`
      ];

      if (memory.projectSlug) {
        lines.push(`Project: ${memory.projectSlug}`);
      }

      lines.push('Content:');
      lines.push(memory.content);

      return lines.join('\n');
    }).join('\n\n')
  : '';

return [{
  json: {
    query: base.query,
    projectSlug: base.projectSlug,
    memoryCount: memories.length,
    contextBlock,
    memories
  }
}];
